SELECT ?year (COUNT(?driver) AS ?count) WHERE {
  ?event wdt:P31 wd:Q39255;
         rdfs:label ?name;
         wdt:P585 ?date.
  FILTER (LANG(?name) = 'en' && CONTAINS(STR(?name), 'Canadian Grand Prix')).
  BIND(YEAR(?date) AS ?year).
  FILTER (?year IN (2015, 2016)).
  ?event wdt:P513 ?session.
  ?session wdt:P31 wd:Q15973444.
  ?session wdt:P527 ?driver.
} GROUP BY ?year ORDER BY ?count

